# lambda_handler.py — Action Group Lambda with Vex validation
import json
from vex_sdk import VexClient, ActionGroupResponseValidator

vex = VexClient(api_key="vex_your_api_key_here")
validator = ActionGroupResponseValidator(strict_mode=True)

def build_action_group_response(
    action_group: str,
    api_path: str,
    http_method: str,
    status_code: int,
    response_body: dict
) -> dict:
    """Build a correctly structured Bedrock Action Group response."""
    response = {
        "messageVersion": "1.0",
        "response": {
            "actionGroup": action_group,
            "apiPath": api_path,
            "httpMethod": http_method,
            "httpStatusCode": status_code,
            "responseBody": {
                "application/json": {
                    "body": json.dumps(response_body)
                }
            }
        }
    }

    # Validate with Vex before returning to the agent
    validation = validator.validate(response)
    if not validation.is_valid:
        raise ValueError(
            f"Action group response failed Vex validation: {validation.errors}"
        )

    return response

def lambda_handler(event, context):
    action_group = event["actionGroup"]
    api_path = event["apiPath"]
    http_method = event["httpMethod"]
    parameters = event.get("parameters", [])

    try:
        if api_path == "/check-inventory" and http_method == "GET":
            product_id = next(
                p["value"] for p in parameters if p["name"] == "productId"
            )
            # Business logic
            inventory_count = get_inventory_count(product_id)  # your function

            return build_action_group_response(
                action_group=action_group,
                api_path=api_path,
                http_method=http_method,
                status_code=200,
                response_body={"productId": product_id, "count": inventory_count, "inStock": inventory_count > 0}
            )

        elif api_path == "/create-order" and http_method == "POST":
            request_body = event.get("requestBody", {}).get("content", {}).get("application/json", {}).get("properties", [])
            order_data = {prop["name"]: prop["value"] for prop in request_body}
            order_id = create_order(order_data)  # your function

            return build_action_group_response(
                action_group=action_group,
                api_path=api_path,
                http_method=http_method,
                status_code=201,
                response_body={"orderId": order_id, "status": "created"}
            )

    except Exception as e:
        # Return a valid error response — never let Lambda throw unhandled
        return build_action_group_response(
            action_group=action_group,
            api_path=api_path,
            http_method=http_method,
            status_code=500,
            response_body={"error": str(e), "success": False}
        )

// bedrock-agent-service.ts
import {
  BedrockAgentRuntimeClient,
  InvokeAgentCommand,
  InvokeAgentCommandInput,
  ResponseStream
} from "@aws-sdk/client-bedrock-agent-runtime";
import { VexClient, VerificationContext, VexPolicyViolationError } from "vex-sdk";

const bedrockClient = new BedrockAgentRuntimeClient({ region: "us-east-1" });

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  policySet: {
    name: "bedrock-agents-production",
    policies: [
      { type: "action-group-schema", validateResponseStructure: true },
      { type: "session-continuity", alertOnSessionReset: true },
      { type: "knowledge-base-coverage", minCitationCoverage: 0.7 },
      { type: "domain-policy", rules: ["no-competitor-mention", "escalate-billing-over-10000"] }
    ]
  }
});

interface AgentInvocationResult {
  completion: string;
  citations: Array<{ content: string; references: string[] }>;
  sessionId: string;
  vexVerification: Record<string, unknown>;
}

async function invokeAgentWithVex(
  agentId: string,
  agentAliasId: string,
  sessionId: string,
  inputText: string
): Promise<AgentInvocationResult> {
  const input: InvokeAgentCommandInput = {
    agentId,
    agentAliasId,
    sessionId,
    inputText,
    enableTrace: true // Required for Vex trace inspection
  };

  const command = new InvokeAgentCommand(input);
  const response = await bedrockClient.send(command);

  let completionText = "";
  const traceEvents: unknown[] = [];
  const citations: Array<{ content: string; references: string[] }> = [];

  // Process the async iterable event stream
  for await (const event of response.completion as AsyncIterable<ResponseStream>) {
    if ("chunk" in event && event.chunk) {
      const chunkText = new TextDecoder().decode(event.chunk.bytes);
      completionText += chunkText;

      // Extract knowledge base citations
      if (event.chunk.attribution?.citations) {
        for (const citation of event.chunk.attribution.citations) {
          citations.push({
            content: citation.generatedResponsePart?.textResponsePart?.text ?? "",
            references: (citation.retrievedReferences ?? []).map(
              (ref) => ref.content?.text ?? ""
            )
          });
        }
      }
    }

    if ("trace" in event && event.trace) {
      traceEvents.push(event.trace);
    }
  }

  // Build Vex verification context
  const vexContext: VerificationContext = {
    sessionId,
    agentId,
    input: inputText,
    output: completionText,
    traces: traceEvents,
    citations,
    framework: "amazon-bedrock-agents"
  };

  try {
    const verificationResult = await vex.verify(vexContext);
    return {
      completion: completionText,
      citations,
      sessionId,
      vexVerification: verificationResult.toObject()
    };
  } catch (error) {
    if (error instanceof VexPolicyViolationError) {
      console.error("Vex policy violation detected:", error.violations);
      // Return a safe fallback response instead of the violating completion
      return {
        completion: error.fallbackResponse ?? "I'm unable to provide a response to that request.",
        citations: [],
        sessionId,
        vexVerification: { violated: true, violations: error.violations }
      };
    }
    throw error;
  }
}

// Next.js API route usage
export async function POST(request: Request) {
  const { agentId, agentAliasId, sessionId, message } = await request.json();

  const result = await invokeAgentWithVex(
    agentId,
    agentAliasId,
    sessionId ?? crypto.randomUUID(),
    message
  );

  return Response.json(result);
}
